设计学生成绩管理系统：要求
（1）有N个学生，每个学生的信息包含学号，姓名，和M门课的成绩
   即有结构体数组
   #define N 30
   #define M 5
   struct student
{
 char num[10];
 char name[20];
 float score[M];
 float stu_avg;
 float cource_avg;
}stu[N]
（2）利用函数void input(struct student *p,int n, int m ) 完成数据的输入
（3）利用函数 void process(struct student *p, int n, int m) 计算每个学生M门课的平均成绩；
（4）利用函数 void output(struct student *p, int n, int m) 将处理结果输出；
（5）设计main()函数进行测试。

下面是我为您编写的学生成绩管理系统实现代码：

```c++
#include <iostream>
#include <string>
using namespace std;

#define N 30 // 最大学生数
#define M 5  // 最大考试科目数

struct Student
{
    string num;          // 学号
    string name;         // 姓名
    float score[M];      // 每门考试成绩
    float stu_avg;       // 学生平均分
    float course_avg;    // 每门课程平均分
};

/**
 * @brief 输入学生信息和考试成绩
 * @param p 结构体指针，指向保存学生信息的数组首地址
 * @param n 学生数目
 * @param m 考试科目数
 */
void input(Student *p, int n, int m)
{
    for (int i = 0; i < n; i++)
    {
        cout << "请输入第 " << i + 1 << " 个学生的信息：" << endl;
        cout << "学号：";
        cin >> p[i].num;
        cout << "姓名：";
        cin >> p[i].name;
        for (int j = 0; j < m; j++)
        {
            cout << "第 " << j + 1 << " 门成绩：";
            cin >> p[i].score[j];
        }
    }
}

/**
 * @brief 计算每个学生的平均成绩和每门课的平均成绩
 * @param p 结构体指针，指向保存学生信息的数组首地址
 * @param n 学生数目
 * @param m 考试科目数
 */
void process(Student *p, int n, int m)
{
    // 计算每个学生的平均成绩
    for (int i = 0; i < n; i++)
    {
        float sum = 0;
        for (int j = 0; j < m; j++)
        {
            sum += p[i].score[j];
        }
        p[i].stu_avg = sum / m;
    }

    // 计算每门课的平均成绩
    for (int j = 0; j < m; j++)
    {
        float sum = 0;
        for (int i = 0; i < n; i++)
        {
            sum += p[i].score[j];
        }
        p[0].course_avg = sum / n;
    }
}

/**
 * @brief 输出学生信息和计算结果
 * @param p 结构体指针，指向保存学生信息的数组首地址
 * @param n 学生数目
 * @param m 考试科目数
 */
void output(Student *p, int n, int m)
{
    cout << "学号\t姓名\t";
    for (int i = 0; i < m; i++)
    {
        cout << "科目" << i + 1 << "成绩\t";
    }
    cout << "平均分" << endl;
    for (int i = 0; i < n; i++)
    {
        cout << p[i].num << "\t" << p[i].name << "\t";
        for (int j = 0; j < m; j++)
        {
            cout << p[i].score[j] << "\t";
        }
        cout << p[i].stu_avg << endl;
    }
    cout << "平均分\t\t\t";
    for (int j = 0; j < m; j++)
    {
        cout << p[0].course_avg << "\t";
    }
    cout << endl;
}

int main()
{
    int n, m;
    cout << "请输入学生人数：";
    cin >> n;
    cout << "请输入考试科目数：";
    cin >> m;

    Student stu[N];
    input(stu, n, m);

    process(stu, n, m);

    output(stu, n, m);

    return 0;
}
```

在这个程序中，首先定义了一个名为`Student`的结构体来保存每个学生的信息，包括学号、姓名、每门考试的成绩、学生平均分和每门课的平均分。在`input()`函数中，程序通过循环查询用户输入每个学生的信息，包括学号、姓名和5个考试科目的成绩，然后将这些信息存储到结构体数组中。在`process()`函数中，程序利用两个嵌套循环分别计算每个学生的平均成绩和每门课的平均成绩，并将这些值保存到结构体中。最后，在`output()`函数中，程序使用循环输出每个学生的学号、姓名、考试成绩和平均分，以及所有考试科目的平均分。
